def check_number(num):
    if num > 0:
        return 'Positive'
    elif num < 0:
        return 'Negative'
    else:
        return 'Zero'

def even_or_odd(num):
    if num % 2 == 0:
        if num > 0:
            return 'Positive Even'
        else:
            return 'Negative Even'
    else:
        if num > 0:
            return 'Positive Odd'
        else:
            return 'Negative Odd'

def check_range(num):
    if 1 <= num <= 10:
        return 'In range'
    else:
        return 'Out of range'
